// generar_235_prevencion_mini_resumenes.js
// CHIQUI Entre Señales — Mini-resúmenes de estado en Salud Preventiva
//
// Cada sección de Prevención muestra ahora, al lado de su nombre, una
// píldora que resume su estado de un vistazo (sin abrir la sección):
//
// 💉 Vacunas → "Al día" (verde) / "En 10 días" (amarillo) / "Vencido"
//    (rojo), según la próxima fecha más cercana pendiente.
// 💊 Antiparasitarios → igual criterio que vacunas.
// 👁️ Observaciones → "1 activa" (naranjo) y/o "2 resueltas" (verde).
// 🩹 Medicamentos → "1 activo" (azul, color reservado) / "Sin activos".
// 🏥 Enfermedades → "1 activa" (rojo, cuenta activas y crónicas) /
//    "Resueltas" (verde).
// 📄 Exámenes y 🔍 Revisiones → "Hace N días" desde el último registro.
//
// Los colores siguen el semáforo de salud de la app. Las fechas usan
// zona horaria de Chile. Es solo lectura: no cambia ningún flujo ni
// dato, solo agrega contexto visual en los encabezados.
//
// Solo reescribe app/prevencion/page.tsx. No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_235_prevencion_mini_resumenes.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/prevencion/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 1 archivo escrito correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
